mapper.select:
SELECT ir.id, ir.production_line_id AS productionLineId, pl.line_name AS productionLineName, ir.inbound_no AS inboundNo, ir.material_code_id AS materialCodeId, ir.material_code AS materialCode, ir.material_name AS materialName, ir.model_specification AS modelSpecification, ir.warehouse_location_id AS warehouseLocationId, ir.area_code AS areaCode, ir.location_code AS locationCode, ir.inbound_qty AS inboundQty, ir.unit_price AS unitPrice, ir.inbound_amount AS inboundAmount, ir.inbound_status AS inboundStatus, ir.inventory_property AS inventoryProperty, ir.inbound_type AS inboundType, ir.inbound_date AS inboundDate, ir.creator_id AS creatorId, su.username AS creatorUsername, su.real_name AS creatorName, ir.created_at AS createdAt, ir.updated_at AS updatedAt FROM inbound_request ir LEFT JOIN production_line pl ON ir.production_line_id = pl.id LEFT JOIN sys_user su ON ir.creator_id = su.id
AND ir.creator_id = #{creatorId} AND ir.production_line_id = #{productionLineId} AND ir.inbound_no LIKE CONCAT('%', #{inboundNo}, '%') AND ir.material_code LIKE CONCAT('%', #{materialCode}, '%') AND ir.material_name LIKE CONCAT('%', #{materialName}, '%') AND ir.area_code LIKE CONCAT('%', #{areaCode}, '%') AND ir.location_code LIKE CONCAT('%', #{locationCode}, '%') AND ir.inbound_status = #{inboundStatus}
ORDER BY ir.id DESC

